export const getListTrackerItemsUrl = (trackerId: number,
    params?: ListTrackerItemsParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/trackers/${trackerId}/items?${stringifiedParams}` : `/api/trackers/${trackerId}/items`
}

