export const getSharedTracker = async (token: string, options?: RequestInit): Promise<PublicTrackerView> => {

  return customFetch<PublicTrackerView>(getGetSharedTrackerUrl(token),
  {
    ...options,
    method: 'GET'


  }
);}





export const getGetSharedTrackerQueryKey = (token: string,) => {
    return [
    `/api/share/${token}`
    ] as const;
    }


export const getGetSharedTrackerQueryOptions = <TData = Awaited<ReturnType<typeof getSharedTracker>>, TError = ErrorType<void>>(token: string, options?: { query?:UseQueryOptions<Awaited<ReturnType<typeof getSharedTracker>>, TError, TData>, request?: SecondParameter<typeof customFetch>}
) => {

const {query: queryOptions, request: requestOptions} = options ?? {};

  const queryKey =  queryOptions?.queryKey ?? getGetSharedTrackerQueryKey(token);



    const queryFn: QueryFunction<Awaited<ReturnType<typeof getSharedTracker>>> = ({ signal }) => getSharedTracker(token, { signal, ...requestOptions });





   return  { queryKey, queryFn, enabled: !!(token), ...queryOptions} as UseQueryOptions<Awaited<ReturnType<typeof getSharedTracker>>, TError, TData> & { queryKey: QueryKey }
}

export type GetSharedTrackerQueryResult = NonNullable<Awaited<ReturnType<typeof getSharedTracker>>>
export type GetSharedTrackerQueryError = ErrorType<void>


/**
 * @summary Publicly view a shared tracker (no auth required)
 */

export function useGetSharedTracker<TData = Awaited<ReturnType<typeof getSharedTracker>>, TError = ErrorType<void>>(
 token: string, options?: { query?:UseQueryOptions<Awaited<ReturnType<typeof getSharedTracker>>, TError, TData>, request?: SecondParameter<typeof customFetch>}

 ):  UseQueryResult<TData, TError> & { queryKey: QueryKey } {

  const queryOptions = getGetSharedTrackerQueryOptions(token,options)

  const query = useQuery(queryOptions) as  UseQueryResult<TData, TError> & { queryKey: QueryKey };

  return { ...query, queryKey: queryOptions.queryKey };
}







